scwin.f_Save = async function () {
  if (!(await scwin.f_SaveValid("SaveTemporary"))) return;
  if (ds_fix_work.isUpdated() == false && ds_fix_work_standard.getUpdatedIndex().length == 0 && ds_fix_work_unit.getUpdatedIndex().length == 0 && ds_fix_driver.getUpdatedIndex().length == 0 && ds_repair_circula_parts.getUpdatedIndex().length == 0 && ds_fix_work_parts.getUpdatedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["작업지시 기본정보 및 상세정보"]);
  } else {
    if (ica_wrkStDt.getValue() + "" + em_wrkStHh.getValue() > ica_wrkEndDt.getValue() + "" + em_wrkEndHh.getValue()) {
      await $c.win.alert($p, "작업시작일시를 작업완료일시 이전으로 입력하여 주십시오.");
      ica_wrkStDt.setFocus();
      return;
    }
    if (ica_inDt.getValue() + "" + em_inHh.getValue() > ica_outDt.getValue() + "" + em_outHh.getValue()) {
      await $c.win.alert($p, "입고일시를 출고일시 이전으로 입력하여 주십시오");
      ica_inDt.setFocus();
      return;
    }
    ds_fix_work.set("vehclNo", txt_vehclNo.getValue());
    if (ica_wrkStDt.getValue() != "" && ica_wrkEndDt.getValue() != "") {
      em_needDt.setValue($c.date.diffDate($p, ica_wrkStDt.getValue(), ica_wrkEndDt.getValue()));
    }
    if (scwin.cvUpdate == true) {
      // TODO: ds_fix_work.UseChangeInfo = false equivalent
    }
    for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
      if (ds_fix_work_parts.getCellData(row, "partQty") == "0") {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_013, ["소요부품의 사용수량", "0"]);
        return;
      }
    }
    sbm_save.action = scwin.saveAction;
    await $c.sbm.execute($p, sbm_save);
    $c.gus.cfDisableKeyData($p);
    $c.gus.cfDisableObjects($p, [btn_Save_center]);
    scwin.f_ctrlApplyFixWorkStandardBtn(true);
    scwin.f_ctrlGrdBtn(true);
    scwin.f_ctrlGrdEnable(false);
    em_fixWrkPlCd.setReadOnly(true);
    scwin.f_Retrieve();
  }
};
scwin.f_SaveValid = async function (saveType) {
  $c.gus.cfRefreshMandSign($p);
  let chk = await $c.gus.cfValidate($p, [tb_work]);
  if (!chk) return false;
  if (saveType == "SaveTemporary") {
    let chk2 = await $c.gus.cfValidate($p, [tbl_eq]);
    if (!chk2) return false;
    let chk3 = await $c.gus.cfValidate($p, [em_wrkIntendDt, em_endIntendDt]);
    if (!chk3) return false;
    if (em_wrkIntendDt.getValue() != "" && em_endIntendDt.getValue() != "") {
      if (!$c.gus.cfIsAfterDate($p, em_wrkIntendDt.getValue(), em_endIntendDt.getValue())) {
        await $c.win.alert($p, "작업예정일자는 종료예정일자 이전이어야 합니다.");
        ica_wrkStDt.setFocus();
        return false;
      }
    }
    if (ica_wrkStDt.getValue().trim() != "" && ica_wrkEndDt.getValue().trim() != "") {
      if (ds_fix_work.get("homeClsCd") == "TR") {
        let stYm = ica_wrkStDt.getValue().trim().substring(0, 6);
        let edYm = ica_wrkEndDt.getValue().trim().substring(0, 6);
        if (stYm != edYm) {
          await $c.win.alert($p, "작업시작월과 종료월은 동일 해야 합니다.");
          return false;
        }
      }
    }
  }
  ds_fix_work.set("vehclNo", txt_vehclNo.getValue());
  if (ica_wrkStDt.getValue() != "" && ica_wrkEndDt.getValue() != "") {
    em_needDt.setValue($c.date.diffDate($p, ica_wrkStDt.getValue(), ica_wrkEndDt.getValue()));
  }
  return true;
};
