scwin.f_RetrieveStockCustomer = function (row) {
  switch (ds_fix_work_parts.getCellData(row, "inClsCd")) {
    case "1":
      if (ds_fix_work_parts.getCellData(row, "partCd") == "") return;
      scwin.f_openCommPopUpGrid(7, row, 'T');
      break;
    case "2":
      ds_fix_work_parts.setCellData(row, "clntNo", "");
      ds_fix_work_parts.setCellData(row, "clntNm", "");
      ds_fix_work_parts.setCellData(row, "outUpr", 0);
      ds_fix_work_parts.setCellData(row, "totAmt", 0);
      ds_fix_work_parts.setCellData(row, "vatAmt", 0);
      break;
    case "3":
      if (ds_fix_work_parts.getCellData(row, "partCd") == "") return;
      scwin.f_openCommPopUpGrid(8, row, 'T');
      break;
  }
};
scwin.f_setIntendDt = function () {
  if (em_wrkIntendDt.getValue() == "" && ica_wrkStDt.getValue() != "") {
    em_wrkIntendDt.setValue(ica_wrkStDt.getValue());
  }
  if (em_endIntendDt.getValue() == "" && ica_wrkEndDt.getValue() != "") {
    em_endIntendDt.setValue(ica_wrkEndDt.getValue());
  }
};
scwin.f_setAdjustment = function () {
  let partAmt = 0;
  if (em_partAmt.getValue() == "") em_partAmt.setValue("0");
  for (let row = 0; row < ds_fix_work_parts.getRowCount(); row++) {
    partAmt = parseInt(em_partAmt.getValue()) + parseInt(ds_fix_work_parts.getCellData(row, "totAmt") || "0");
  }
  em_partAmt.setValue(partAmt);
  if (em_wages.getValue() == "") em_wages.setValue("0");
  if (lux_selfOutordClsCd.getValue() == "IN") {
    let wages = 0;
    for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
      if (em_adptWages.getValue() == "") em_adptWages.setValue("0");
      if (em_adptWages.getValue() != "0" && ds_fix_work_unit.getCellData(row, "wrkHhCnt") != "0") {
        wages += parseInt(em_adptWages.getValue()) * parseInt(ds_fix_work_unit.getCellData(row, "wrkHhCnt") || "0");
      }
    }
    em_wages.setValue(wages);
    em_totAmt.setValue(parseInt(em_partAmt.getValue()));
  } else {
    let wages = 0;
    for (let row = 0; row < ds_fix_work_unit.getRowCount(); row++) {
      wages += parseInt(ds_fix_work_unit.getCellData(row, "bilgWages") || "0");
    }
    em_wages.setValue(wages);
    em_totAmt.setValue(parseInt(em_wages.getValue()) + parseInt(em_partAmt.getValue()));
  }
  if (em_totAmt.getValue() != "") {
    em_vatAmt.setValue(parseFloat(em_totAmt.getValue()) / 10);
  }
};
